apply plugin: 'com.android.application'

project.ext.envFile = ".env"
apply from: project(':react-native-config').projectDir.getPath() + "/dotenv.gradle"

apply plugin: 'org.jetbrains.kotlin.android'
apply plugin: 'com.facebook.react'

apply plugin: 'kotlin-android'
apply plugin: 'kotlin-kapt'
apply plugin: 'kotlinx-serialization'
apply plugin: 'kotlin-parcelize'

apply from: '../../node_modules/react-native-code-push/android/codepush.gradle'

apply plugin: 'com.google.firebase.firebase-perf'


import com.android.build.OutputFile

def enableSeparateBuildPerCPUArchitecture = true

react {
  /* Folders */
    //   The root of your project, i.e. where "package.json" lives. Default is '..'
    // root = file("../")
    //   The folder where the react-native NPM package is. Default is ../node_modules/react-native
    // reactNativeDir = file("../node_modules/react-native")
    //   The folder where the react-native Codegen package is. Default is ../node_modules/@react-native/codegen
    // codegenDir = file("../node_modules/@react-native/codegen")
    //   The cli.js file which is the React Native CLI entrypoint. Default is ../node_modules/react-native/cli.js
    // cliFile = file("../node_modules/react-native/cli.js")

    /* Variants */
    //   The list of variants to that are debuggable. For those we're going to
    //   skip the bundling of the JS bundle and the assets. By default is just 'debug'.
    //   If you add flavors like lite, prod, etc. you'll have to list your debuggableVariants.
    // debuggableVariants = ["liteDebug", "prodDebug"]

    /* Bundling */
    //   A list containing the node command and its flags. Default is just 'node'.
    // nodeExecutableAndArgs = ["node"]
    //
    //   The command to run when bundling. By default is 'bundle'
    // bundleCommand = "ram-bundle"
    //
    //   The path to the CLI configuration file. Default is empty.
    // bundleConfig = file(../rn-cli.config.js)
    //
    //   The name of the generated asset file containing your JS bundle
    // bundleAssetName = "MyApplication.android.bundle"
    //
    //   The entry file for bundle generation. Default is 'index.android.js' or 'index.js'
    // entryFile = file("../js/MyApplication.android.js")
    //
    //   A list of extra flags to pass to the 'bundle' commands.
    //   See https://github.com/react-native-community/cli/blob/main/docs/commands.md#bundle
    // extraPackagerArgs = []

    /* Hermes Commands */
    //   The hermes compiler command to run. By default it is 'hermesc'
    // hermesCommand = "$rootDir/my-custom-hermesc/bin/hermesc"
    //
    //   The list of flags to pass to the Hermes compiler. By default is "-O", "-output-source-map"
    // hermesFlags = ["-O", "-output-source-map"]
 }

/**
 * Set this to true to Run Proguard on Release builds to minify the Java bytecode.
 */
def enableProguardInReleaseBuilds = true

/**
 * The preferred build flavor of JavaScriptCore (JSC)
 *
 * For example, to use the international variant, you can use:
 * `def jscFlavor = 'org.webkit:android-jsc-intl:+'`
 *
 * The international variant includes ICU i18n library and necessary data
 * allowing to use e.g. `Date.toLocaleString` and `String.localeCompare` that
 * give correct results when using with locales other than en-US. Note that
 * this variant is about 6MiB larger per architecture than default.
 */
def jscFlavor = 'org.webkit:android-jsc:+'

android {
  ndkVersion rootProject.ext.ndkVersion
  buildToolsVersion rootProject.ext.buildToolsVersion
  compileSdk rootProject.ext.compileSdkVersion

  namespace "com.semparar.semparar.minhaconta2018"

  defaultConfig {
    applicationId 'com.semparar.semparar.minhaconta2018'
    minSdkVersion rootProject.ext.minSdkVersion
    targetSdkVersion rootProject.ext.targetSdkVersion
    versionCode 4797843
    versionName "4.18.0"
    missingDimensionStrategy 'react-native-camera', 'general'
    manifestPlaceholders = [googleApiKey: "AIzaSyAoUozl6M2ylj2JZ3apX11oB9Bl3wLkOnU"]
  }

  aaptOptions {
    cruncherEnabled = false
  }

  compileOptions {
    sourceCompatibility JavaVersion.VERSION_1_8
    targetCompatibility JavaVersion.VERSION_1_8
  }

    sourceSets {
      main {
        jniLibs.srcDirs = ['libs']
      }
    }


  splits {
    abi {
      reset()
      enable enableSeparateBuildPerCPUArchitecture
      universalApk true
      include 'armeabi-v7a', 'x86', 'arm64-v8a', 'x86_64'
    }
  }
  signingConfigs {
    debug {
      if (project.hasProperty('MYAPP_RELEASE_STORE_FILE')) {
        storeFile file(MYAPP_RELEASE_STORE_FILE)
        storePassword MYAPP_RELEASE_STORE_PASSWORD
        keyAlias MYAPP_RELEASE_KEY_ALIAS
        keyPassword MYAPP_RELEASE_KEY_PASSWORD
      }
    }
    releaseStaging {
      if (project.hasProperty('MYAPP_RELEASE_STORE_FILE')) {
        storeFile file(MYAPP_RELEASE_STORE_FILE)
        storePassword MYAPP_RELEASE_STORE_PASSWORD
        keyAlias MYAPP_RELEASE_KEY_ALIAS
        keyPassword MYAPP_RELEASE_KEY_PASSWORD
      }
    }
    release {
      if (project.hasProperty('MYAPP_RELEASE_STORE_FILE')) {
        storeFile file(MYAPP_RELEASE_STORE_FILE)
        storePassword MYAPP_RELEASE_STORE_PASSWORD
        keyAlias MYAPP_RELEASE_KEY_ALIAS
        keyPassword MYAPP_RELEASE_KEY_PASSWORD
      }
    }
  }
  buildTypes {
    debug {
      // Note: CodePush updates should not be tested in Debug mode as they are overriden by the RN packager. However, because CodePush checks for updates in all modes, we must supply a key.
      resValue 'string', 'CodePushDeploymentKey', '"9-OzIEqI7u3Hd7QYRqULLYdzBPJLl-2wwXehM"'
      signingConfig signingConfigs.release
    }

    releaseStaging {
      resValue 'string', 'CodePushDeploymentKey', '"nNAqb1nwEJH7S6rIvA0yG8hQbWaLAoa1bEBgN"'

      // Note: It is a good idea to provide matchingFallbacks for the new buildType you create to prevent build issues
      // Add the following line if not already there
      matchingFallbacks = ['release']
      signingConfig signingConfigs.release
    }

    release {
      resValue 'string', 'CodePushDeploymentKey', '"FeR374exRePBO5dpIuWR1o5mrULKlNIolL-4S"'
      signingConfig signingConfigs.release

      crunchPngs false // or true
      shrinkResources true

      minifyEnabled enableProguardInReleaseBuilds
      proguardFiles getDefaultProguardFile('proguard-android.txt'), 'proguard-rules.pro'
    }
  }

  buildFeatures {
    dataBinding true
  }

  applicationVariants.all { variant ->
    variant.outputs.each { output ->
      // For each separate APK per architecture, set a unique version code as described here:
      // https://developer.android.com/studio/build/configure-apk-splits.html
      def versionCodes = ['armeabi-v7a': 1, 'x86': 2, 'arm64-v8a': 3, 'x86_64': 4]
      def abi = output.getFilter(OutputFile.ABI)
      if (abi != null) {  // null for the universal-debug, universal-release variants
        output.versionCodeOverride =
          versionCodes.get(abi) * 2 + defaultConfig.versionCode
      }
    }
  }

  packagingOptions {
    pickFirst '**/armeabi-v7a/libc++_shared.so'
    pickFirst '**/x86/libc++_shared.so'
    pickFirst '**/arm64-v8a/libc++_shared.so'
    pickFirst '**/x86_64/libc++_shared.so'
    pickFirst '**/x86/libjsc.so'
    pickFirst '**/armeabi-v7a/libjsc.so'
    pickFirst '**/libjsc.so'
  }
}

repositories {
  flatDir {
    dirs 'libs'
  }
}

dependencies {
  implementation project(':react-native-fs')
  implementation 'org.webkit:android-jsc:+'

  implementation project(':react-native-camera')
  implementation 'androidx.appcompat:appcompat:1.0.2'
  implementation 'androidx.annotation:annotation:1.0.2'

  implementation 'org.jetbrains.kotlinx:kotlinx-coroutines-core:1.6.4'
  implementation 'org.jetbrains.kotlinx:kotlinx-coroutines-android:1.6.4'
  // SDK Unico
  implementation 'io.unico:capture:5.45.0'

  // SDK Salesforce chat
  // implementation 'com.salesforce.service:messaging-inapp-ui:1.3.0'
  implementation('com.salesforce.service:messaging-inapp-ui:1.3.0')
  implementation('com.salesforce.service:messaging-inapp-core:1.3.0')
  implementation "androidx.lifecycle:lifecycle-viewmodel-ktx:2.5.1"

  implementation "com.salesforce.service:chat-ui:4.3.2"
  implementation "com.salesforce.service:chat-core:4.3.2"


  // Provide the Android support library (you might already have this or a similar dependency)
  implementation 'com.android.support:support-core-utils:24.2.1'
  implementation project(':react-native-file-picker')
  implementation project(':react-native-push-notification')
  implementation project(':react-native-bluetooth-state-manager')
  // implementation 'com.facebook.android:facebook-android-sdk:[4,5)'
  implementation('com.facebook.react:react-android')
  implementation 'androidx.paging:paging-common-android:3.3.2'

  implementation("com.facebook.react:flipper-integration")
    if (hermesEnabled.toBoolean()) {
      implementation('com.facebook.react:hermes-android')
    } else {
      implementation jscFlavor
    }
  implementation 'com.squareup.retrofit2:adapter-rxjava2:2.3.0'

  // -------------
  implementation 'com.android.support.constraint:constraint-layout:1.1.3'
  implementation 'androidx.constraintlayout:constraintlayout:2.1.3'
  implementation 'com.google.android.gms:play-services-location:21.0.1'
  implementation 'com.squareup.okhttp3:okhttp:4.9.0'
  implementation 'com.squareup.okhttp3:okhttp-urlconnection:4.9.0'
  implementation 'com.squareup.okhttp3:logging-interceptor:4.9.0'
  implementation 'com.android.support:multidex:2.0.1'
  implementation 'android.arch.persistence.room:runtime:1.1.1'
  implementation 'android.arch.work:work-runtime:1.0.1'

  // Mintech
  implementation(name: 'datacollectionsdk-release', ext: 'aar')
  api 'com.google.code.gson:gson:2.8.6'
  api 'com.squareup.retrofit2:converter-gson:2.9.0'
  api 'io.reactivex.rxjava2:rxjava:2.2.20'
